// src/utils.ts
function isVersionNewer(currentVersion, oldVersion) {
  if (!currentVersion || !oldVersion)
    return false;
  if (currentVersion === oldVersion)
    return false;
  const current = currentVersion.split(".").map(Number);
  const old = oldVersion.split(".").map(Number);
  for (let i = 0; i < 3; i++) {
    const v1 = current[i] || 0;
    const v2 = old[i] || 0;
    if (v1 > v2)
      return true;
    if (v1 < v2)
      return false;
  }
  return false;
}

